		return getReloadableResourceBundleMessageSource().getMessage(code, args, Locale.getDefault());
	}

	/**
	 * 정의된 메세지 조회
	 * @param code - 메세지 코드
	 * @param args - 매개변수
	 * @param locale - 로케일
	 * @return String
	 */	
