    	String[] sysIps = resultVO.getSysIp().split("[.]");
    	resultVO.setSysIp1(sysIps[0]);
    	resultVO.setSysIp2(sysIps[1]);
    	resultVO.setSysIp3(sysIps[2]);
    	resultVO.setSysIp4(sysIps[3]);

